1843 /// Order may have elements assigned special value (size) which is out of
1844 /// bounds. Such indices only appear on places which correspond to undef values
1845 /// (see canReuseExtract for details) and used in order to avoid undef values
1846 /// have effect on operands ordering.
1847 /// The first loop below simply finds all unused indices and then the next loop
1848 /// nest assigns these indices for undef values positions.
1849 /// As an example below Order has two undef positions and they have assigned
1850 /// values 3 and 7 respectively:
1851 /// before:  6 9 5 4 9 2 1 0
1852 /// after:   6 3 5 4 7 2 1 0
1853 static void fixupOrderingIndices(MutableArrayRef<unsigned> Order) {
1854   const size_t Sz = Order.size();
1855   SmallBitVector UnusedIndices(Sz, /*t=*/true);
1856   SmallBitVector MaskedIndices(Sz);
1857   for (unsigned I = 0; I < Sz; ++I) {
1858     if (Order[I] < Sz)
1859       UnusedIndices.reset(Order[I]);
1860     else
1861       MaskedIndices.set(I);
1862   }
1863   if (MaskedIndices.none())
1864     return;
1865   assert(UnusedIndices.count() == MaskedIndices.count() &&
1866          "Non-synced masked/available indices.");
1867   int Idx = UnusedIndices.find_first();
1868   int MIdx = MaskedIndices.find_first();
1869   while (MIdx >= 0) {
1870     assert(Idx >= 0 && "Indices must be synced.");
1871     Order[MIdx] = Idx;
1872     Idx = UnusedIndices.find_next(Idx);
1873     MIdx = MaskedIndices.find_next(MIdx);
1874   }
1875 }
