23076 bool BoUpSLP::BlockScheduling::extendSchedulingRegion(
23077     Value *V, const InstructionsState &S) {
23078   Instruction *I = dyn_cast<Instruction>(V);
23079   assert(I && "bundle member must be an instruction");
23080   if (getScheduleData(I))
23081     return true;
23082   if (!ScheduleStart) {
23083     // It's the first instruction in the new region.
23084     initScheduleData(I, I->getNextNode(), nullptr, nullptr);
