23088     LLVM_DEBUG(dbgs() << "SLP:  initialize schedule region to " << *I << "\n");
23089     return true;
23090   }
23091   // Search up and down at the same time, because we don't know if the new
23092   // instruction is above or below the existing scheduling region.
23093   // Ignore debug info (and other "AssumeLike" intrinsics) so that's not counted
23094   // against the budget. Otherwise debug info could affect codegen.
23095   BasicBlock::reverse_iterator UpIter =
23096       ++ScheduleStart->getIterator().getReverse();
23097   BasicBlock::reverse_iterator UpperEnd = BB->rend();
23098   BasicBlock::iterator DownIter = ScheduleEnd->getIterator();
23099   BasicBlock::iterator LowerEnd = BB->end();
23100   auto IsAssumeLikeIntr = [](const Instruction &I) {
23101     if (auto *II = dyn_cast<IntrinsicInst>(&I))
23102       return II->isAssumeLikeIntrinsic();
23103     return false;
23104   };
23105   UpIter = std::find_if_not(UpIter, UpperEnd, IsAssumeLikeIntr);
23106   DownIter = std::find_if_not(DownIter, LowerEnd, IsAssumeLikeIntr);
23107   while (UpIter != UpperEnd && DownIter != LowerEnd && &*UpIter != I &&
23108          &*DownIter != I) {
23109     if (++ScheduleRegionSize > ScheduleRegionSizeLimit) {
23110       LLVM_DEBUG(dbgs() << "SLP:  exceeded schedule region size limit\n");
23111       return false;
23112     }
23113 
23114     ++UpIter;
23115     ++DownIter;
23116 
23117     UpIter = std::find_if_not(UpIter, UpperEnd, IsAssumeLikeIntr);
23118     DownIter = std::find_if_not(DownIter, LowerEnd, IsAssumeLikeIntr);
23119   }
23120   if (DownIter == LowerEnd || (UpIter != UpperEnd && &*UpIter == I)) {
23121     assert(I->getParent() == ScheduleStart->getParent() &&
23122            "Instruction is in wrong basic block.");
