23142 void BoUpSLP::BlockScheduling::initScheduleData(Instruction *FromI,
23143                                                 Instruction *ToI,
23144                                                 ScheduleData *PrevLoadStore,
23145                                                 ScheduleData *NextLoadStore) {
23146   ScheduleData *CurrentLoadStore = PrevLoadStore;
23147   for (Instruction *I = FromI; I != ToI; I = I->getNextNode()) {
23148     // No need to allocate data for non-schedulable instructions.
23149     if (isa<PHINode>(I))
23150       continue;
23151     ScheduleData *SD = ScheduleDataMap.lookup(I);
23152     if (!SD) {
23153       SD = allocateScheduleDataChunks();
23154       ScheduleDataMap[I] = SD;
23155     }
23156     assert(!isInSchedulingRegion(*SD) &&
23157            "new ScheduleData already in scheduling region");
23158     SD->init(SchedulingRegionID, I);
23159 
23160     auto CanIgnoreLoad = [](const Instruction *I) {
23161       const auto *LI = dyn_cast<LoadInst>(I);
23162       // If there is a simple load marked as invariant, we can ignore it.
23163       // But, in the (unlikely) case of non-simple invariant load,
23164       // we should not ignore it.
23165       return LI && LI->isSimple() &&
23166              LI->getMetadata(LLVMContext::MD_invariant_load);
23167     };
23168 
23169     if (I->mayReadOrWriteMemory() &&
23170         // Simple InvariantLoad does not depend on other memory accesses.
23171         !CanIgnoreLoad(I) &&
23172         (!isa<IntrinsicInst>(I) ||
23173          (cast<IntrinsicInst>(I)->getIntrinsicID() != Intrinsic::sideeffect &&
23174           cast<IntrinsicInst>(I)->getIntrinsicID() !=
23175               Intrinsic::pseudoprobe))) {
23176       // Update the linked list of memory accessing instructions.
23177       if (CurrentLoadStore) {
23178         CurrentLoadStore->setNextLoadStore(SD);
23179       } else {
23180         FirstLoadStoreInRegion = SD;
23181       }
23182       CurrentLoadStore = SD;
23183     }
23184 
23185     if (match(I, m_Intrinsic<Intrinsic::stacksave>()) ||
23186         match(I, m_Intrinsic<Intrinsic::stackrestore>()))
23187       RegionHasStackSave = true;
23188   }
23189   if (NextLoadStore) {
23190     if (CurrentLoadStore)
23191       CurrentLoadStore->setNextLoadStore(NextLoadStore);
23192   } else {
23193     LastLoadStoreInRegion = CurrentLoadStore;
23194   }
23195 }
