25211         SortedStores, [&PtrDist, SI, this](const RelatedStoreInsts &StoreSeq) {
25212           PtrDist = StoreSeq.getPointerDiff(*SI, *DL, *SE);
25213           return PtrDist.has_value();
25214         });
25215 
25216     // We did not find a comparable store, start a new group.
25217     if (RelatedStores == SortedStores.end()) {
25218       SortedStores.emplace_back(Idx, Stores);
25219       return;
25220     }
25221 
25222     // If there is already a store in the group with the same PtrDiff, try to
25223     // vectorize the existing instructions before adding the current store.
25224     // Otherwise, insert this store and keep collecting.
25225     if (std::optional<unsigned> PrevInst =
