25240     // Check that we do not try to vectorize stores of different types.
25241     if (PrevValTy != SI->getValueOperand()->getType()) {
25242       for (RelatedStoreInsts &StoreSeq : SortedStores)
25243         TryToVectorize(StoreSeq.getStores());
25244       SortedStores.clear();
25245       PrevValTy = SI->getValueOperand()->getType();
25246     }
25247     FillStoresSet(I, SI);
25248   }
25249 
25250   // Final vectorization attempt.
25251   for (RelatedStoreInsts &StoreSeq : SortedStores)
25252     TryToVectorize(StoreSeq.getStores());
