25257 void SLPVectorizerPass::collectSeedInstructions(BasicBlock *BB) {
25258   // Initialize the collections. We will make a single pass over the block.
25259   Stores.clear();
25260   GEPs.clear();
25261 
25262   // Visit the store and getelementptr instructions in BB and organize them in
25263   // Stores and GEPs according to the underlying objects of their pointer
25264   // operands.
25265   for (Instruction &I : *BB) {
25266     // Ignore store instructions that are volatile or have a pointer operand
25267     // that doesn't point to a scalar type.
25268     if (auto *SI = dyn_cast<StoreInst>(&I)) {
25269       if (!SI->isSimple())
25270         continue;
25271       if (!isValidElementType(SI->getValueOperand()->getType()))
25272         continue;
25273       Stores[getUnderlyingObject(SI->getPointerOperand())].push_back(SI);
25274     }
25275 
25276     // Ignore getelementptr instructions that have more than one index, a
25277     // constant index, or a pointer operand that doesn't point to a scalar
25278     // type.
25279     else if (auto *GEP = dyn_cast<GetElementPtrInst>(&I)) {
25280       if (GEP->getNumIndices() != 1)
25281         continue;
25282       Value *Idx = GEP->idx_begin()->get();
25283       if (isa<Constant>(Idx))
25284         continue;
25285       if (!isValidElementType(Idx->getType()))
25286         continue;
25287       if (GEP->getType()->isVectorTy())
25288         continue;
25289       GEPs[GEP->getPointerOperand()].push_back(GEP);
25290     }
25291   }
25292 }
