1816 /// \param ExtendingManyInputs Supports reshuffling of the mask with not only
1817 /// one but two input vectors.
1818 static void addMask(SmallVectorImpl<int> &Mask, ArrayRef<int> SubMask,
1819                     bool ExtendingManyInputs = false) {
1820   if (SubMask.empty())
1821     return;
1822   assert(
1823       (!ExtendingManyInputs || SubMask.size() > Mask.size() ||
1824        // Check if input scalars were extended to match the size of other node.
1825        (SubMask.size() == Mask.size() && Mask.back() == PoisonMaskElem)) &&
1826       "SubMask with many inputs support must be larger than the mask.");
1827   if (Mask.empty()) {
1828     Mask.append(SubMask.begin(), SubMask.end());
1829     return;
1830   }
1831   SmallVector<int> NewMask(SubMask.size(), PoisonMaskElem);
1832   int TermValue = std::min(Mask.size(), SubMask.size());
1833   for (int I = 0, E = SubMask.size(); I < E; ++I) {
1834     if (SubMask[I] == PoisonMaskElem ||
1835         (!ExtendingManyInputs &&
1836          (SubMask[I] >= TermValue || Mask[SubMask[I]] >= TermValue)))
1837       continue;
1838     NewMask[I] = Mask[SubMask[I]];
1839   }
1840   Mask.swap(NewMask);
