1976 /// Returns true if widened type of \p Ty elements with size \p Sz represents
1977 /// full vector type, i.e. adding extra element results in extra parts upon type
1978 /// legalization.
1979 static bool hasFullVectorsOrPowerOf2(const TargetTransformInfo &TTI, Type *Ty,
1980                                      unsigned Sz) {
1981   if (Sz <= 1)
1982     return false;
1983   if (!isValidElementType(Ty) && !isa<FixedVectorType>(Ty))
1984     return false;
1985   if (has_single_bit(Sz))
1986     return true;
1987   const unsigned NumParts = TTI.getNumberOfParts(getWidenedType(Ty, Sz));
1988   return NumParts > 0 && NumParts < Sz && has_single_bit(Sz / NumParts) &&
1989          Sz % NumParts == 0;
1990 }
