1992 /// Returns number of parts, the type \p VecTy will be split at the codegen
1993 /// phase. If the type is going to be scalarized or does not uses whole
1994 /// registers, returns 1.
1995 static unsigned
1996 getNumberOfParts(const TargetTransformInfo &TTI, VectorType *VecTy,
1997                  const unsigned Limit = std::numeric_limits<unsigned>::max()) {
1998   unsigned NumParts = TTI.getNumberOfParts(VecTy);
1999   if (NumParts == 0 || NumParts >= Limit)
2000     return 1;
2001   unsigned Sz = getNumElements(VecTy);
2002   if (NumParts >= Sz || Sz % NumParts != 0 ||
2003       !hasFullVectorsOrPowerOf2(TTI, VecTy->getElementType(), Sz / NumParts))
2004     return 1;
2005   return NumParts;
2006 }
