1170   bool add(const Instruction *I) {
1171     assert(isa<BinaryOperator>(I) &&
1172            "BinOpSameOpcodeHelper only accepts BinaryOperator.");
1173     unsigned Opcode = I->getOpcode();
1174     MaskType OpcodeInMaskForm;
1175     // Prefer Shl, AShr, Mul, Add, Sub, And, Or and Xor over MainOp.
1176     switch (Opcode) {
1177     case Instruction::Shl:
1178       OpcodeInMaskForm = ShlBIT;
1179       break;
1180     case Instruction::AShr:
1181       OpcodeInMaskForm = AShrBIT;
1182       break;
1183     case Instruction::Mul:
1184       OpcodeInMaskForm = MulBIT;
1185       break;
1186     case Instruction::Add:
1187       OpcodeInMaskForm = AddBIT;
1188       break;
1189     case Instruction::Sub:
1190       OpcodeInMaskForm = SubBIT;
1191       break;
1192     case Instruction::And:
1193       OpcodeInMaskForm = AndBIT;
1194       break;
1195     case Instruction::Or:
1196       OpcodeInMaskForm = OrBIT;
1197       break;
1198     case Instruction::Xor:
1199       OpcodeInMaskForm = XorBIT;
1200       break;
1201     default:
1202       return MainOp.equal(Opcode) ||
1203              (initializeAltOp(I) && AltOp.equal(Opcode));
1204     }
1205     MaskType InterchangeableMask = OpcodeInMaskForm;
1206     ConstantInt *CI = isBinOpWithConstantInt(I).first;
1207     if (CI) {
1208       constexpr MaskType CanBeAll =
1209           XorBIT | OrBIT | AndBIT | SubBIT | AddBIT | MulBIT | AShrBIT | ShlBIT;
1210       const APInt &CIValue = CI->getValue();
1211       switch (Opcode) {
1212       case Instruction::Shl:
1213         if (CIValue.ult(CIValue.getBitWidth()))
1214           InterchangeableMask = CIValue.isZero() ? CanBeAll : MulBIT | ShlBIT;
1215         if (CIValue.isOne())
1216           InterchangeableMask |= AddBIT;
1217         break;
1218       case Instruction::Mul:
1219         if (CIValue.isOne()) {
1220           InterchangeableMask = CanBeAll;
1221           break;
1222         }
1223         if (CIValue.isPowerOf2())
1224           InterchangeableMask = MulBIT | ShlBIT;
1225         break;
1226       case Instruction::Add:
1227       case Instruction::Sub:
1228         InterchangeableMask = CIValue.isZero() ? CanBeAll : SubBIT | AddBIT;
1229         break;
1230       case Instruction::And:
1231         if (CIValue.isAllOnes())
1232           InterchangeableMask = CanBeAll;
1233         break;
1234       case Instruction::Xor:
1235         if (CIValue.isZero())
1236           InterchangeableMask = XorBIT | OrBIT | SubBIT | AddBIT;
1237         break;
1238       default:
1239         if (CIValue.isZero())
1240           InterchangeableMask = CanBeAll;
1241         break;
1242       }
1243     }
1244     return MainOp.trySet(OpcodeInMaskForm, InterchangeableMask) ||
1245            (initializeAltOp(I) &&
1246             AltOp.trySet(OpcodeInMaskForm, InterchangeableMask));
