1508 /// Find an instruction with a specific opcode in VL.
1509 /// \param VL Array of values to search through. Must contain only Instructions
1510 ///           and PoisonValues.
1511 /// \param Opcode The instruction opcode to search for
1512 /// \returns
1513 /// - The first instruction found with matching opcode
1514 /// - nullptr if no matching instruction is found
1515 static Instruction *findInstructionWithOpcode(ArrayRef<Value *> VL,
1516                                               unsigned Opcode) {
1517   for (Value *V : VL) {
1518     if (isa<PoisonValue>(V))
1519       continue;
1520     assert(isa<Instruction>(V) && "Only accepts PoisonValue and Instruction.");
1521     auto *Inst = cast<Instruction>(V);
1522     if (Inst->getOpcode() == Opcode)
1523       return Inst;
1524   }
1525   return nullptr;
