1530 static bool areCompatibleCmpOps(Value *BaseOp0, Value *BaseOp1, Value *Op0,
1531                                 Value *Op1, const TargetLibraryInfo &TLI) {
1532   return (isConstant(BaseOp0) && isConstant(Op0)) ||
