2683     /// Go through the operands of \p LHS and \p RHS recursively until
2684     /// MaxLevel, and return the cummulative score. \p U1 and \p U2 are
2685     /// the users of \p LHS and \p RHS (that is \p LHS and \p RHS are operands
2686     /// of \p U1 and \p U2), except at the beginning of the recursion where
2687     /// these are set to nullptr.
2688     ///
2689     /// For example:
2690     /// \verbatim
2691     ///  A[0]  B[0]  A[1]  B[1]  C[0] D[0]  B[1] A[1]
2692     ///     \ /         \ /         \ /        \ /
2693     ///      +           +           +          +
2694     ///     G1          G2          G3         G4
2695     /// \endverbatim
2696     /// The getScoreAtLevelRec(G1, G2) function will try to match the nodes at
2697     /// each level recursively, accumulating the score. It starts from matching
2698     /// the additions at level 0, then moves on to the loads (level 1). The
2699     /// score of G1 and G2 is higher than G1 and G3, because {A[0],A[1]} and
2700     /// {B[0],B[1]} match with LookAheadHeuristics::ScoreConsecutiveLoads, while
2701     /// {A[0],C[0]} has a score of LookAheadHeuristics::ScoreFail.
2702     /// Please note that the order of the operands does not matter, as we
2703     /// evaluate the score of all profitable combinations of operands. In
2704     /// other words the score of G1 and G4 is the same as G1 and G2. This
2705     /// heuristic is based on ideas described in:
2706     ///   Look-ahead SLP: Auto-vectorization in the presence of commutative
2707     ///   operations, CGO 2018 by Vasileios Porpodas, Rodrigo C. O. Rocha,
2708     ///   Luís F. W. Góes
2709     int getScoreAtLevelRec(Value *LHS, Value *RHS, Instruction *U1,
2710                            Instruction *U2, int CurrLevel,
2711                            ArrayRef<Value *> MainAltOps) const {
2712 
2713       // Get the shallow score of V1 and V2.
2714       int ShallowScoreAtThisLevel =
2715           getShallowScore(LHS, RHS, U1, U2, MainAltOps);
2716 
2717       // If reached MaxLevel,
2718       //  or if V1 and V2 are not instructions,
2719       //  or if they are SPLAT,
2720       //  or if they are not consecutive,
2721       //  or if profitable to vectorize loads or extractelements, early return
2722       //  the current cost.
2723       auto *I1 = dyn_cast<Instruction>(LHS);
2724       auto *I2 = dyn_cast<Instruction>(RHS);
2725       if (CurrLevel == MaxLevel || !(I1 && I2) || I1 == I2 ||
2726           ShallowScoreAtThisLevel == LookAheadHeuristics::ScoreFail ||
2727           (((isa<LoadInst>(I1) && isa<LoadInst>(I2)) ||
2728             (I1->getNumOperands() > 2 && I2->getNumOperands() > 2) ||
2729             (isa<ExtractElementInst>(I1) && isa<ExtractElementInst>(I2))) &&
2730            ShallowScoreAtThisLevel))
2731         return ShallowScoreAtThisLevel;
2732       assert(I1 && I2 && "Should have early exited.");
2733 
2734       // Contains the I2 operand indexes that got matched with I1 operands.
2735       SmallSet<unsigned, 4> Op2Used;
2736 
2737       // Recursion towards the operands of I1 and I2. We are trying all possible
2738       // operand pairs, and keeping track of the best score.
2739       if (I1->getNumOperands() != I2->getNumOperands())
2740         return LookAheadHeuristics::ScoreSameOpcode;
2741       for (unsigned OpIdx1 = 0, NumOperands1 = I1->getNumOperands();
2742            OpIdx1 != NumOperands1; ++OpIdx1) {
2743         // Try to pair op1I with the best operand of I2.
2744         int MaxTmpScore = 0;
2745         unsigned MaxOpIdx2 = 0;
2746         bool FoundBest = false;
2747         // If I2 is commutative try all combinations.
2748         unsigned FromIdx = isCommutative(I2) ? 0 : OpIdx1;
2749         unsigned ToIdx = isCommutative(I2)
2750                              ? I2->getNumOperands()
2751                              : std::min(I2->getNumOperands(), OpIdx1 + 1);
2752         assert(FromIdx <= ToIdx && "Bad index");
2753         for (unsigned OpIdx2 = FromIdx; OpIdx2 != ToIdx; ++OpIdx2) {
2754           // Skip operands already paired with OpIdx1.
2755           if (Op2Used.count(OpIdx2))
2756             continue;
2757           // Recursively calculate the cost at each level
2758           int TmpScore =
2759               getScoreAtLevelRec(I1->getOperand(OpIdx1), I2->getOperand(OpIdx2),
2760                                  I1, I2, CurrLevel + 1, {});
2761           // Look for the best score.
2762           if (TmpScore > LookAheadHeuristics::ScoreFail &&
2763               TmpScore > MaxTmpScore) {
2764             MaxTmpScore = TmpScore;
2765             MaxOpIdx2 = OpIdx2;
2766             FoundBest = true;
2767           }
2768         }
2769         if (FoundBest) {
2770           // Pair {OpIdx1, MaxOpIdx2} was found to be best. Never revisit it.
2771           Op2Used.insert(MaxOpIdx2);
2772           ShallowScoreAtThisLevel += MaxTmpScore;
2773         }
2774       }
2775       return ShallowScoreAtThisLevel;
2776     }
