1006       if (Mask & InterchangeableMask) {
1007         MaskType TempSeenBefore = SeenBefore | OpcodeInMaskForm;
1008         MaskType TempMask = Mask & InterchangeableMask;
1009         if (!(TempMask & TempSeenBefore))
1010           return false;
1011         Mask = TempMask;
1012         SeenBefore = TempSeenBefore;
1013         return true;
1014       }
1015       return false;
1016     }
1017     bool equal(unsigned Opcode) {
1018       return Opcode == I->getOpcode() && trySet(MainOpBIT, MainOpBIT);
1019     }
1020     unsigned getOpcode() const {
1021       MaskType Candidate = Mask & SeenBefore;
1022       if (Candidate & MainOpBIT)
1023         return I->getOpcode();
1024       if (Candidate & ShlBIT)
1025         return Instruction::Shl;
1026       if (Candidate & AShrBIT)
1027         return Instruction::AShr;
1028       if (Candidate & MulBIT)
1029         return Instruction::Mul;
1030       if (Candidate & AddBIT)
1031         return Instruction::Add;
1032       if (Candidate & SubBIT)
1033         return Instruction::Sub;
1034       if (Candidate & AndBIT)
1035         return Instruction::And;
1036       if (Candidate & OrBIT)
1037         return Instruction::Or;
1038       if (Candidate & XorBIT)
1039         return Instruction::Xor;
1040       llvm_unreachable("Cannot find interchangeable instruction.");
1041     }
1042 
1043     /// Return true if the instruction can be converted to \p Opcode.
1044     bool hasCandidateOpcode(unsigned Opcode) const {
1045       MaskType Candidate = Mask & SeenBefore;
1046       switch (Opcode) {
1047       case Instruction::Shl:
1048         return Candidate & ShlBIT;
1049       case Instruction::AShr:
1050         return Candidate & AShrBIT;
1051       case Instruction::Mul:
1052         return Candidate & MulBIT;
1053       case Instruction::Add:
1054         return Candidate & AddBIT;
1055       case Instruction::Sub:
1056         return Candidate & SubBIT;
1057       case Instruction::And:
1058         return Candidate & AndBIT;
1059       case Instruction::Or:
1060         return Candidate & OrBIT;
1061       case Instruction::Xor:
1062         return Candidate & XorBIT;
1063       case Instruction::LShr:
1064       case Instruction::FAdd:
1065       case Instruction::FSub:
1066       case Instruction::FMul:
1067       case Instruction::SDiv:
1068       case Instruction::UDiv:
1069       case Instruction::FDiv:
1070       case Instruction::SRem:
1071       case Instruction::URem:
1072       case Instruction::FRem:
1073         return false;
1074       default:
1075         break;
1076       }
1077       llvm_unreachable("Cannot find interchangeable instruction.");
1078     }
1079 
1080     SmallVector<Value *> getOperand(const Instruction *To) const {
1081       unsigned ToOpcode = To->getOpcode();
1082       unsigned FromOpcode = I->getOpcode();
1083       if (FromOpcode == ToOpcode)
1084         return SmallVector<Value *>(I->operands());
1085       assert(binary_search(SupportedOp, ToOpcode) && "Unsupported opcode.");
1086       auto [CI, Pos] = isBinOpWithConstantInt(I);
1087       const APInt &FromCIValue = CI->getValue();
1088       unsigned FromCIValueBitWidth = FromCIValue.getBitWidth();
1089       Type *RHSType = I->getOperand(Pos)->getType();
1090       Constant *RHS;
1091       switch (FromOpcode) {
1092       case Instruction::Shl:
1093         if (ToOpcode == Instruction::Add && FromCIValue.isOne())
1094           return {I->getOperand(0), I->getOperand(0)};
1095         if (ToOpcode == Instruction::Mul) {
1096           RHS = ConstantInt::get(
1097               RHSType, APInt::getOneBitSet(FromCIValueBitWidth,
1098                                            FromCIValue.getZExtValue()));
1099         } else {
1100           assert(FromCIValue.isZero() && "Cannot convert the instruction.");
1101           RHS = ConstantExpr::getBinOpIdentity(ToOpcode, RHSType,
1102                                                /*AllowRHSConstant=*/true);
1103         }
1104         break;
1105       case Instruction::Mul:
1106         assert(FromCIValue.isPowerOf2() && "Cannot convert the instruction.");
1107         if (ToOpcode == Instruction::Shl) {
1108           RHS = ConstantInt::get(
1109               RHSType, APInt(FromCIValueBitWidth, FromCIValue.logBase2()));
1110         } else {
1111           assert(FromCIValue.isOne() && "Cannot convert the instruction.");
1112           RHS = ConstantExpr::getBinOpIdentity(ToOpcode, RHSType,
1113                                                /*AllowRHSConstant=*/true);
1114         }
1115         break;
1116       case Instruction::Add:
1117       case Instruction::Sub:
1118         if (FromCIValue.isZero()) {
1119           RHS = ConstantExpr::getBinOpIdentity(ToOpcode, RHSType,
1120                                                /*AllowRHSConstant=*/true);
1121         } else {
1122           assert(is_contained({Instruction::Add, Instruction::Sub}, ToOpcode) &&
1123                  "Cannot convert the instruction.");
1124           APInt NegatedVal = APInt(FromCIValue);
1125           NegatedVal.negate();
1126           RHS = ConstantInt::get(RHSType, NegatedVal);
1127         }
1128         break;
1129       case Instruction::And:
1130         assert(FromCIValue.isAllOnes() && "Cannot convert the instruction.");
1131         RHS = ConstantExpr::getBinOpIdentity(ToOpcode, RHSType,
1132                                              /*AllowRHSConstant=*/true);
1133         break;
1134       default:
1135         assert(FromCIValue.isZero() && "Cannot convert the instruction.");
1136         RHS = ConstantExpr::getBinOpIdentity(ToOpcode, RHSType,
1137                                              /*AllowRHSConstant=*/true);
1138         break;
1139       }
1140       Value *LHS = I->getOperand(1 - Pos);
1141       // constant + x cannot be -constant - x
1142       // instead, it should be x - -constant
1143       if (Pos == 1 ||
1144           ((FromOpcode == Instruction::Add || FromOpcode == Instruction::Or ||
1145             FromOpcode == Instruction::Xor) &&
1146            ToOpcode == Instruction::Sub))
1147         return SmallVector<Value *>({LHS, RHS});
1148       return SmallVector<Value *>({RHS, LHS});
1149     }
1150   };
1151   InterchangeableInfo MainOp;
1152   InterchangeableInfo AltOp;
1153   bool isValidForAlternation(const Instruction *I) const {
1154     return ::isValidForAlternation(MainOp.I->getOpcode()) &&
1155            ::isValidForAlternation(I->getOpcode());
1156   }
1157   bool initializeAltOp(const Instruction *I) {
1158     if (AltOp.I)
1159       return true;
1160     if (!isValidForAlternation(I))
1161       return false;
1162     AltOp.I = I;
1163     return true;
1164   }
